<?php $studios = App\Models\Studio::withCount('seats')->get(); foreach($studios as $studio) { if ($studio->seats_count == 0) { $seats = []; $now = now(); for ($r = 0; $r < $studio->rows; $r++) { $rowLabel = chr(65 + $r); for ($c = 1; $c <= $studio->cols; $c++) { $seats[] = ['studio_id' => $studio->id, 'row_label' => $rowLabel, 'seat_number' => $c, 'code' => $rowLabel . $c, 'type' => 'regular', 'is_active' => true, 'created_at' => $now, 'updated_at' => $now]; } } App\Models\Seat::insert($seats); echo 'Inserted seats for studio ' . $studio->id . PHP_EOL; } }
